LAYER
	NAME "edificaciones"
	GROUP "MPU"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/mpu/mpu/edificaciones.html"
	#FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, cod_sector, id_ubigeo, id_sector, cod_mzna, id_mzna, cod_lote, id_lote, codi_edifi, id_edifica, area_grafi, peri_grafi, geom FROM geo.tg_edificaciones) as mpu using unique gid using srid=32718"
	INCLUDE "configuracion/postgresql_mpu.map"
	PROJECTION
		"init=epsg:32718"
	END
	CLASSITEM "gid"
	METADATA
		"wms_group_title" "MPU"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Edificaciones"
		"wms_abstract" "Edificaciones || Municipalidad Provincial de Urubamba - Cusco :: Perú"
		"wms_credit" "MPU"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "807683.9653000003 8526364.0129 814882.6846000003 8531884.0174"
		"wms_srs" "EPSG:32718"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
		NAME "Edificaciones"
		EXPRESSION /./
		STYLE
			COLOR 242 188 160
			OUTLINECOLOR 185 150 131
			WIDTH 1
		END
		LABEL
			TEXT "[codi_edifi]"
			COLOR 185 150 131
			FONT "FreeSans"
			TYPE truetype
			SIZE 7
			POSITION cc
			PARTIALS false
		END
	END
END # Layer